const raw = $input.first().json;
const incoming = raw.body || raw;
const config = {
  SUPABASE_URL: 'YOUR_SUPABASE_URL',
  SUPABASE_SERVICE_KEY: 'YOUR_SUPABASE_SERVICE_KEY',
  ANTHROPIC_API_KEY: 'YOUR_ANTHROPIC_API_KEY',
  GRYNOW_WEBSITE_ID: 'YOUR_GRYNOW_WEBSITE_ID',
  MYWALL_WEBSITE_ID: 'YOUR_MYWALL_WEBSITE_ID',
  IGYGROW_WEBSITE_ID: 'YOUR_IGYGROW_WEBSITE_ID',
  MEMORY_WEBHOOK_URL: 'http://localhost:5678/webhook/seo-memory',
  REVIEW_WEBHOOK_URL: 'http://localhost:5678/webhook/seo-review',
  PIPELINE_WEBHOOK_URL: 'http://localhost:5678/webhook/seo-pipeline',
};
return [{ json: { ...config, ...incoming } }];

const fetch=(u,o={})=>new Promise((res,rej)=>{const iH=u.startsWith('https');const lib=require(iH?'https':'http');const m=u.match(/^https?:\/\/([^/:]+)(?::(\d+))?(\/[^?#]*)?(\?[^#]*)?/);if(!m)return rej(new Error('Bad URL: '+u));const body=o.body||null;const req=lib.request({hostname:m[1],port:m[2]?+m[2]:(iH?443:80),path:(m[3]||'/')+(m[4]||''),method:o.method||'GET',headers:{...(o.headers||{}),...(body?{'Content-Length':Buffer.byteLength(body)}:{})}},r=>{let d='';r.on('data',c=>d+=c);r.on('end',()=>res({ok:r.statusCode<300,status:r.statusCode,json:()=>Promise.resolve(JSON.parse(d||'null')),text:()=>Promise.resolve(d)}));});req.on('error',rej);if(body)req.write(body);req.end();});

const cfg = $('Config').first().json;

// Normalise intake — new requests are flat, rework has nested intake object
const isFlat = !!cfg.topic;
const intake = isFlat ? cfg : (cfg.intake && cfg.intake.topic ? cfg.intake : cfg);
const requestId   = cfg.request_id;
const startFrom   = cfg.start_from || 'research';
const isRework    = cfg.is_rework || false;
const reworkFb    = cfg.rework_feedback || null;
let websiteId = ({ grynow: cfg.GRYNOW_WEBSITE_ID, mywall: cfg.MYWALL_WEBSITE_ID, igygrow: cfg.IGYGROW_WEBSITE_ID }[intake.website_slug] || cfg.GRYNOW_WEBSITE_ID);

const sbUrl = cfg.SUPABASE_URL;
const sbKey = cfg.SUPABASE_SERVICE_KEY;
const sbH   = { 'apikey': sbKey, 'Authorization': 'Bearer ' + sbKey, 'Content-Type': 'application/json' };

async function sbGet(path) {
  const r = await fetch(sbUrl + '/rest/v1/' + path, { headers: { apikey: sbKey, Authorization: 'Bearer ' + sbKey } });
  return r.ok ? r.json() : [];
}
async function sbPatch(table, filter, body) {
  await fetch(`${sbUrl}/rest/v1/${table}?${filter}`, { method: 'PATCH', headers: sbH, body: JSON.stringify(body) });
}
async function claude(system, user, maxTokens) {
  const r = await fetch('https://api.anthropic.com/v1/messages', {
    method: 'POST',
    headers: { 'x-api-key': cfg.ANTHROPIC_API_KEY, 'anthropic-version': '2023-06-01', 'Content-Type': 'application/json' },
    body: JSON.stringify({ model: 'claude-sonnet-4-6', max_tokens: maxTokens || 4096, system, messages: [{ role: 'user', content: user }] })
  });
  const d = await r.json();
  if (!d.content) throw new Error('Claude error: ' + JSON.stringify(d));
  return d.content[0].text;
}
function parseJSON(text) {
  try {
    const m = text.match(/```json\s*([\s\S]*?)```/) || text.match(/([\[{][\s\S]*[\]}])/);
    return JSON.parse(m ? m[1] : text);
  } catch(e) { return { _parse_error: true, raw: text.substring(0, 300) }; }
}

let researchNotes = cfg.research_brief || null;
let contentPlan   = cfg.strategy_brief || null;

// Self-fetch intake + prior research/plan when called from Review Handler (rework, write-only)
if (startFrom === 'write' && !intake.topic && requestId) {
  const rr = await fetch(`${sbUrl}/rest/v1/content_requests?id=eq.${requestId}&select=*,websites(slug,name)`, { headers: { apikey: sbKey, Authorization: 'Bearer '+sbKey } });
  const rrows = await rr.json();
  if (rrows && rrows[0]) {
    const rreq = rrows[0];
    Object.assign(intake, {
      website_slug: rreq.websites?.slug || 'grynow',
      website_name: rreq.websites?.name || 'GryNow',
      website_url:  ({ grynow: 'https://grynow.in', mywall: 'https://mywall.me', igygrow: 'https://www.igygrow.com' }[rreq.websites?.slug] || 'https://grynow.in'),
      placement: rreq.placement, content_type: rreq.content_type, topic: rreq.topic,
      keywords: rreq.keywords, keywords_raw: (rreq.keywords||[]).join(', '),
      layout_notes: rreq.layout_notes||'', additional_brief: rreq.additional_brief||''
    });
    researchNotes = researchNotes || rreq.research_brief;
    contentPlan   = contentPlan   || rreq.strategy_brief;
  }
  websiteId = ({ grynow: cfg.GRYNOW_WEBSITE_ID, mywall: cfg.MYWALL_WEBSITE_ID, igygrow: cfg.IGYGROW_WEBSITE_ID }[intake.website_slug] || cfg.GRYNOW_WEBSITE_ID);
}

const outlineSeed = (intake.layout_notes && intake.layout_notes.trim())
  ? intake.layout_notes.trim()
  : 'No outline supplied by the brief — propose a sensible H1/H2/H3 structure for the topic.';

// ───────────────────────────────────────────── RESEARCH + PLAN ──
if (startFrom !== 'write') {

  // ── AGENT 1: CONTENT RESEARCHER ──
  await sbPatch('content_requests', `id=eq.${requestId}`, { status: 'researching' });

  const [kbData, memData] = await Promise.all([
    sbGet(`knowledge_base?select=category,content&or=(website_id.eq.${websiteId},website_id.is.null)`).catch(()=>[]),
    sbGet(`memory_patterns?select=pattern_type,pattern&or=(website_id.eq.${websiteId},website_id.is.null)&order=frequency.desc&limit=20`).catch(()=>[]),
  ]);
  const kb = {}; (Array.isArray(kbData)?kbData:[]).forEach(d=>{ kb[d.category]=d.content; });
  const audience = kb['audience'] || intake.additional_brief || `General readers interested in ${intake.topic}.`;
  const siteKnowledge = [kb['business-overview'], kb['site-overview']].filter(Boolean).join('\n\n') || 'No business knowledge available.';

  const researchSys = `You are a Senior Content Researcher. Your job is NOT to write the article — you prepare the structured research notes a writer will use.\nFor every section in the outline you must: explain the key concept in simple terms; gather the most important facts, insights and explanations; identify common questions readers may have; find practical examples, use cases and scenarios; surface relevant statistics or supporting data when available; note common misconceptions or mistakes readers make; list important subtopics to cover; and write detailed writer notes.\nDo not write final article content. Produce structured research notes only.`;
  const researchMsg = `Topic: ${intake.topic}\nContent type: ${intake.content_type}\nTarget audience: ${audience}\nBusiness / site knowledge (factual grounding — do not contradict):\n${siteKnowledge}\nSearch intent: infer from the topic (informational / commercial / transactional / navigational)\nReference keywords (context only — do NOT do keyword analysis): ${intake.keywords_raw || (intake.keywords||[]).join(', ') || 'none'}\nContent outline / structure from the brief:\n${outlineSeed}\nAdditional brief: ${intake.additional_brief || 'None'}\n\nReturn ONLY valid JSON in this exact shape:\n{"target_audience":"","search_intent":"informational","sections":[{"heading":"","key_points":[],"reader_questions":[],"examples":[],"supporting_data":[],"misconceptions":[],"subtopics":[],"writer_notes":""}]}`;

  researchNotes = parseJSON(await claude(researchSys, researchMsg, 4096));
  await sbPatch('content_requests', `id=eq.${requestId}`, { research_brief: researchNotes, status: 'strategizing' });

  // ── AGENT 2: CONTENT PLANNER ──
  const toneHint = intake.placement === 'on-page' ? 'FIRST PERSON — the brand speaks as "we"/"our".' : 'THIRD PERSON — refer to the brand by name, never "we".';
  const planSys = `You are a Senior Content Planner. Using the research notes, produce a firm editorial plan the writer will follow exactly. You make content decisions only — do NOT do SEO keyword placement, schema markup, or internal-link optimisation. Return ONLY valid JSON.`;
  const planMsg = `${intake.content_type} | ${intake.placement} → ${toneHint}\nTopic: ${intake.topic}\nOutline / structure from the brief:\n${outlineSeed}\n\nResearch Notes:\n${JSON.stringify(researchNotes,null,2)}\n\nReturn ONLY JSON:\n{"target_audience":"","search_intent":"informational","word_count_target":0,"word_count_rationale":"","depth":"in-depth","depth_rationale":"","tone":"","content_angle":"","outline":[{"level":"h1","text":"","notes":""}],"cta_text":"","cta_placement":"end","special_instructions":""}`;

  contentPlan = parseJSON(await claude(planSys, planMsg, 4096));
  await sbPatch('content_requests', `id=eq.${requestId}`, { strategy_brief: contentPlan, status: 'drafting' });
}

// ──────────────────────────────────────────── AGENT 3: WRITER ──
const versionsRes = await sbGet(`content_versions?select=version_number&request_id=eq.${requestId}&order=version_number.desc&limit=1`);
const versionNumber = (Array.isArray(versionsRes)&&versionsRes.length) ? versionsRes[0].version_number+1 : 1;

const [kbW, patW, samW] = await Promise.all([
  sbGet(`knowledge_base?select=category,content&or=(website_id.eq.${websiteId},website_id.is.null)`).catch(()=>[]),
  sbGet(`memory_patterns?select=pattern_type,pattern&or=(website_id.eq.${websiteId},website_id.is.null)&order=frequency.desc&limit=20`).catch(()=>[]),
  sbGet(`content_archive?select=topic,content_excerpt&website_id=eq.${websiteId}&content_type=eq.${intake.content_type}&placement=eq.${intake.placement}&order=approved_at.desc&limit=3`).catch(()=>[]),
]);

const kbw = {}; (Array.isArray(kbW)?kbW:[]).forEach(d=>{ kbw[d.category]=d.content; });
const businessKnowledge = [kbw['business-overview'], kbw['site-overview']].filter(Boolean).join('\n\n') || 'Digital platform.';
const toneD = intake.placement==='on-page'
  ? `FIRST PERSON — You ARE ${intake.website_name}. Use "we","our","us". Never third person.`
  : `THIRD PERSON — Authoritative writer. Refer to ${intake.website_name} by name. NEVER "we"/"our".`;
const pos = (Array.isArray(patW)?patW:[]).filter(p=>p.pattern_type==='positive').map(p=>'- '+p.pattern).join('\n')||'Set the standard.';
const neg = (Array.isArray(patW)?patW:[]).filter(p=>p.pattern_type==='negative').map(p=>'- '+p.pattern).join('\n')||'None yet.';
const samp = (Array.isArray(samW)?samW:[]).map(s=>`Topic: ${s.topic}\nExcerpt: ${s.content_excerpt||''}`).join('\n\n---\n\n')||'No samples yet.';
const reworkSec = isRework&&reworkFb ? `\n## REWORK FEEDBACK\nFeedback: ${reworkFb.feedback_text}\nCategory: ${reworkFb.category} | Severity: ${reworkFb.severity}\nRe-read your previous draft and properly rework the affected sections — do not just patch.\n` : '';

const plan = contentPlan || {};
const wSys = `You are a Senior Content Writer for ${intake.website_name}.\n\nTONE: ${toneD}\n\nBusiness: ${businessKnowledge}\nBrand Voice: ${kbw['brand-voice']||'Professional, clear, value-focused.'}\n\nYour responsibilities: follow the outline exactly; expand the research notes into clear, engaging content; explain concepts in a reader-friendly way; add examples naturally; maintain logical flow between sections; avoid repetition; keep paragraphs short and scannable; use bullets and lists where useful; match the brand voice. Do NOT perform SEO keyword analysis or optimisation.\nFor each section: introduce the idea, explain it clearly, add practical examples, address common reader questions, and transition naturally to the next section.\nFollow these patterns:\n${pos}\nAvoid:\n${neg}\nStyle samples:\n${samp}`;
const wMsg = `Topic: ${intake.topic}\nContent type: ${intake.content_type} | Placement: ${intake.placement}\nTarget audience: ${plan.target_audience || (researchNotes||{}).target_audience || intake.additional_brief || 'General readers'}\nSearch intent: ${plan.search_intent || (researchNotes||{}).search_intent || 'informational'}\nTarget length: ${plan.word_count_target||1000} words (±10%) | Depth: ${plan.depth||'in-depth'}\nContent angle: ${plan.content_angle||''}\nCTA: ${plan.cta_text||''} (placement: ${plan.cta_placement||'end'})\nSpecial instructions: ${plan.special_instructions||'None'}\n${reworkSec}\nContent Plan / Outline:\n${JSON.stringify(plan,null,2)}\n\nResearch Notes:\n${JSON.stringify(researchNotes,null,2)}\n\nWrite the full ${intake.content_type} now. Output ONLY the article content in Markdown, starting with the H1. Do not include any metadata, notes, or commentary.`;

const contentMd = (await claude(wSys, wMsg, 8096)).trim();
const wordCount = (contentMd.replace(/[#>*_`\[\]()\-]/g,' ').match(/\b[\w']+\b/g) || []).length;

return [{ json: {
  content_markdown: contentMd,
  word_count:       wordCount,
  version_number:   versionNumber,
  request_id:       requestId,
  intake, researchNotes, contentPlan
}}];
